{"content": "     1|import { CURRENCY } from '@/lib/constants';
     2|
     3|/**
     4| * Formats a number as Paraguayan Guaraníes (₲)
     5| * Guaraníes don't use decimal places
     6| *
     7| * @example formatPrice(150000) => "₲ 150.000"
     8| * @example formatPrice(1500000) => "₲ 1.500.000"
     9| */
    10|export function formatPrice(amount: number): string {
    11|  const formatted = new Intl.NumberFormat('es-PY', {
    12|    style: 'decimal',
    13|    minimumFractionDigits: 0,
    14|    maximumFractionDigits: 0,
    15|  }).format(amount);
    16|
    17|  return `${CURRENCY.symbol} ${formatted}`;
    18|}
    19|
    20|/**
    21| * Formats a number as compact Guaraníes for display
    22| *
    23| * @example formatPriceCompact(1500000) => "₲ 1,5M"
    24| */
    25|export function formatPriceCompact(amount: number): string {
    26|  if (amount >= 1_000_000) {
    27|    const millions = amount / 1_000_000;
    28|    return `${CURRENCY.symbol} ${millions.toFixed(1).replace('.', ',')}M`;
    29|  }
    30|  if (amount >= 1_000) {
    31|    const thousands = amount / 1_000;
    32|    return `${CURRENCY.symbol} ${thousands.toFixed(0)}K`;
    33|  }
    34|  return formatPrice(amount);
    35|}
    36|
    37|/**
    38| * Parse a price string back to number
    39| */
    40|export function parsePrice(priceString: string): number {
    41|  const cleaned = priceString.replace(/[^\d]/g, '');
    42|  return parseInt(cleaned, 10) || 0;
    43|}
