    11|
    12|const PRICE_RANGES = [
    13|  { label: 'Hasta ₲ 100.000', min: '0', max: '100000' },
    14|  { label: '₲ 100.000 - ₲ 300.000', min: '100000', max: '300000' },
    15|  { label: '₲ 300.000 - ₲ 500.000', min: '300000', max: '500000' },
    16|  { label: 'Más de ₲ 500.000', min: '500000', max: '' },
    17|];
    18|
    19|const LEVELS = [
    20|  { value: 'principiante', label: 'Principiante' },
    21|  { value: 'intermedio', label: 'Intermedio' },
    22|  { value: 'avanzado', label: 'Avanzado' },
    23|];
    24|
    25|const SORT_OPTIONS = [
    26|  { value: '', label: 'Destacados' },
    27|  { value: 'price_asc', label: 'Precio: Menor a Mayor' },
