    31|
    32|export function CategoryFilters({ slug, currentParams }: FiltersProps) {
    33|  const router = useRouter();
    34|
    35|  function applyFilter(key: string, value: string) {
    36|    const params = new URLSearchParams();
    37|    const current = { ...currentParams, [key]: value };
    38|
    39|    // Handle price ranges
    40|    if (key === 'price') {
    41|      const range = PRICE_RANGES.find((r) => `${r.min}-${r.max}` === value);
    42|      if (range) {
    43|        if (range.min) params.set('min', range.min);
    44|        if (range.max) params.set('max', range.max);
    45|      }
    46|      if (current.sort) params.set('sort', current.sort);
    47|      if (current.level) params.set('level', current.level);
    48|    } else {
    49|      if (value) params.set(key, value);
    50|      if (key !== 'sort' && current.sort) params.set('sort', current.sort);
    51|      if (key !== 'level' && current.level) params.set('level', current.level);
    52|      if (key !== 'price' && current.min) params.set('min', current.min);
