    10|import { PRODUCT_PLACEHOLDERS, DEFAULT_PRODUCT_IMAGE } from '@/lib/images';
    11|import { toast } from 'sonner';
    12|
    13|const LEVEL_BADGES: Record<string, { label: string; dot: string }> = {
    14|  principiante: { label: 'Principiante', dot: 'bg-green-500' },
    15|  intermedio: { label: 'Intermedio', dot: 'bg-yellow-500' },
    16|  avanzado: { label: 'Avanzado', dot: 'bg-red-500' },
    17|};
    18|
    19|interface ProductCardProps {
    20|  product: {
    21|    id: string;
    22|    name: string;
    23|    slug: string;
    24|    price: number;
    25|    compare_at_price: number | null;
    26|    is_featured: boolean;
    27|    experience_level?: string | null;
    28|    image_url?: string | null;
    29|    category_slug?: string;
    30|  };
    31|}
    32|
    33|export function ProductCard({ product }: ProductCardProps) {
    34|  const addItem = useCartStore((s) => s.addItem);
    35|  const productImage = product.image_url || PRODUCT_PLACEHOLDERS[product.category_slug || 'default'] || DEFAULT_PRODUCT_IMAGE;
    36|  const level = product.experience_level
    37|    ? LEVEL_BADGES[product.experience_level.toLowerCase()]
    38|    : null;
    39|  const hasDiscount = product.compare_at_price && product.compare_at_price > product.price;
    40|  const discountPct = hasDiscount
    41|    ? Math.round(((product.compare_at_price! - product.price) / product.compare_at_price!) * 100)
    42|    : 0;
    43|
    44|  function handleAddToCart(e: React.MouseEvent) {
    45|    e.preventDefault();
    46|    e.stopPropagation();
    47|    addItem({
    48|      id: product.id,
    49|      name: product.name,
    50|      price: product.price,
    51|    });
    52|    toast.success('Producto agregado al carrito');
    53|  }
    54|
    55|  return (
    56|    <Link href={`/producto/${product.slug}`}>
    57|      <Card className="group overflow-hidden transition-all hover:ring-2 hover:ring-rose-300">
    58|        <div className="relative aspect-square overflow-hidden">
    59|          <Image
    60|            src={productImage}
    61|            alt={product.name}
    62|            fill
    63|            className="object-cover transition-transform group-hover:scale-105"
    64|          />
    65|          {hasDiscount && (
    66|            <span className="absolute left-2 top-2 rounded-full bg-red-500 px-2 py-0.5 text-xs font-bold text-white">
    67|              -{discountPct}%
    68|            </span>
    69|          )}
    70|          {level && (
    71|            <span className={`absolute right-2 top-2 h-3 w-3 rounded-full ${level.dot}`} title={level.label} />
    72|          )}
    73|        </div>
    74|        <CardContent className="space-y-2 p-3">
    75|          <h3 className="line-clamp-2 text-sm font-medium leading-tight">{product.name}</h3>
    76|          <div className="flex items-center gap-2">
    77|            <span className="text-base font-bold text-rose-600">{formatPrice(product.price)}</span>
    78|            {hasDiscount && (
    79|              <span className="text-xs text-muted-foreground line-through">
    80|                {formatPrice(product.compare_at_price!)}
    81|              </span>
    82|            )}
    83|          </div>
    84|          {level && (
    85|            <Badge variant="secondary" className="text-xs">
    86|              <span className={`mr-1 inline-block h-2 w-2 rounded-full ${level.dot}`} />
    87|              {level.label}
    88|            </Badge>
    89|          )}
    90|          <Button
    91|            onClick={handleAddToCart}
    92|            size="sm"
    93|            className="w-full bg-gradient-to-r from-rose-500 to-purple-600 text-white hover:from-rose-600 hover:to-purple-700"
    94|          >
    95|            Agregar al Carrito
    96|          </Button>
    97|        </CardContent>
    98|      </Card>
    99|    </Link>
   100|  );
